                      </td>
                      <td className="py-2 pl-2 text-right font-mono font-medium text-gray-900">{formatCOP(c.total)}</td>
                      <td className="py-2 pl-1">
                        <button type="button" onClick={() => setLineas(prev => prev.filter((_, i) => i !== idx))}
                          className="text-gray-400 hover:text-red-500 transition-colors">
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {lineas.length > 0 && (
        <div className="flex justify-end">
          <div className="w-64 rounded-xl border border-gray-200 bg-white p-4 flex flex-col gap-2 text-sm">
            <div className="flex justify-between text-gray-600"><span>Subtotal</span><span className="font-mono">{formatCOP(subtotal)}</span></div>
            {descuento > 0 && <div className="flex justify-between text-red-600"><span>Descuento</span><span className="font-mono">-{formatCOP(descuento)}</span></div>}
            <div className="flex justify-between text-gray-600"><span>IVA</span><span className="font-mono">{formatCOP(totalIva)}</span></div>
            <div className="flex justify-between font-bold text-gray-900 border-t border-gray-200 pt-2">
              <span>TOTAL</span><span className="font-mono text-orange-700">{formatCOP(total)}</span>
            </div>
          </div>
        </div>
      )}

      {error && (
        <div className="flex items-center gap-2 rounded-lg bg-red-50 border border-red-200 px-4 py-3 text-sm text-red-700">
          <AlertCircle className="h-4 w-4 shrink-0" /> {error}
        </div>
      )}

      <div className="flex gap-3 justify-end">
        <Button type="button" variant="outline" onClick={() => router.back()}>Cancelar</Button>
        <Button type="submit" disabled={guardando} className="bg-orange-600 hover:bg-orange-700 text-white">
          {guardando ? 'Guardando…' : 'Crear orden de compra'}
        </Button>
      </div>
    </form>
  )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { Button } from '@/components/ui/button'
import { Plus, Star, Edit2, Check, X } from 'lucide-react'

interface Bodega {
  id: string; codigo: string | null; nombre: string; principal: boolean; activa: boolean
}

interface Props { bodegas: Bodega[] }

export function FormBodegas({ bodegas: inicial }: Props) {
  const router = useRouter()
  const [bodegas, setBodegas]     = useState(inicial)
  const [editando, setEditando]   = useState<string | null>(null)
  const [adding, setAdding]       = useState(false)
  const [saving, setSaving]       = useState(false)
  const [nuevo, setNuevo]         = useState({ codigo: '', nombre: '', principal: false })
  const [edit, setEdit]           = useState<Omit<Bodega, 'id'>>({ codigo: '', nombre: '', principal: false, activa: true })

  async function guardarNuevo() {
    if (!nuevo.nombre.trim()) return
    setSaving(true)
    try {
      const res  = await fetch('/api/configuracion/bodegas', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(nuevo),
      })
      if (!res.ok) throw new Error((await res.json()).error)
      setAdding(false)
      setNuevo({ codigo: '', nombre: '', principal: false })
      router.refresh()
    } catch (e: any) {
      alert(e.message)
    } finally {
      setSaving(false)
    }
  }

  function iniciarEdit(b: Bodega) {
    setEditando(b.id)
    setEdit({ codigo: b.codigo ?? '', nombre: b.nombre, principal: b.principal, activa: b.activa })
  }

  async function guardarEdit(id: string) {
    setSaving(true)
    try {
      const res = await fetch('/api/configuracion/bodegas', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id, ...edit }),
      })
      if (!res.ok) throw new Error((await res.json()).error)
      setEditando(null)
      router.refresh()
    } catch (e: any) {
      alert(e.message)
    } finally {
      setSaving(false)
    }
  }

  async function toggleActiva(b: Bodega) {
    const res = await fetch('/api/configuracion/bodegas', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: b.id, activa: !b.activa }),
    })
    if (res.ok) router.refresh()
  }

  return (
    <div className="flex flex-col gap-4">
      <div className="rounded-xl border border-gray-200 bg-white overflow-hidden">
        <div className="flex items-center justify-between px-5 py-4 border-b border-gray-100">
          <h3 className="text-sm font-semibold text-gray-700">{bodegas.length} bodega{bodegas.length !== 1 ? 's' : ''}</h3>
          <Button size="sm" variant="outline" onClick={() => setAdding(true)} disabled={adding}>
            <Plus className="h-4 w-4 mr-1" /> Nueva bodega
          </Button>
        </div>

        <table className="w-full text-sm">
          <thead className="bg-gray-50 border-b border-gray-100">
            <tr>
              <th className="px-4 py-3 text-left font-medium text-gray-500">Código</th>
              <th className="px-4 py-3 text-left font-medium text-gray-500">Nombre</th>
              <th className="px-4 py-3 text-center font-medium text-gray-500">Principal</th>
              <th className="px-4 py-3 text-center font-medium text-gray-500">Activa</th>
              <th className="px-4 py-3" />
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {/* Fila nueva */}
            {adding && (
              <tr className="bg-teal-50">
                <td className="px-4 py-2">
                  <input value={nuevo.codigo} onChange={e => setNuevo(p => ({ ...p, codigo: e.target.value }))}
                    placeholder="BG01" className="w-full h-8 rounded border border-gray-300 px-2 text-sm focus:outline-none focus:ring-1 focus:ring-teal-500" />
                </td>
                <td className="px-4 py-2">
                  <input value={nuevo.nombre} onChange={e => setNuevo(p => ({ ...p, nombre: e.target.value }))}
                    placeholder="Bodega principal" autoFocus
                    className="w-full h-8 rounded border border-gray-300 px-2 text-sm focus:outline-none focus:ring-1 focus:ring-teal-500" />
                </td>
                <td className="px-4 py-2 text-center">
                  <input type="checkbox" checked={nuevo.principal} onChange={e => setNuevo(p => ({ ...p, principal: e.target.checked }))}
                    className="h-4 w-4 rounded border-gray-300 text-teal-600" />
                </td>
                <td className="px-4 py-2 text-center text-gray-400 text-xs">—</td>
                <td className="px-4 py-2 text-right">
                  <div className="flex gap-1 justify-end">
                    <button onClick={guardarNuevo} disabled={saving}
                      className="p-1.5 rounded text-teal-600 hover:bg-teal-100"><Check className="h-4 w-4" /></button>
                    <button onClick={() => setAdding(false)}
                      className="p-1.5 rounded text-gray-400 hover:bg-gray-100"><X className="h-4 w-4" /></button>
                  </div>
                </td>
              </tr>
            )}

            {bodegas.length === 0 && !adding ? (
              <tr><td colSpan={5} className="px-4 py-10 text-center text-gray-400">No hay bodegas</td></tr>
            ) : bodegas.map(b => (
              <tr key={b.id} className={`hover:bg-gray-50 ${!b.activa ? 'opacity-50' : ''}`}>
                {editando === b.id ? (
                  <>
                    <td className="px-4 py-2">
                      <input value={edit.codigo ?? ''} onChange={e => setEdit(p => ({ ...p, codigo: e.target.value }))}
                        className="w-full h-8 rounded border border-gray-300 px-2 text-sm focus:outline-none focus:ring-1 focus:ring-teal-500" />
                    </td>
                    <td className="px-4 py-2">
                      <input value={edit.nombre} onChange={e => setEdit(p => ({ ...p, nombre: e.target.value }))}
                        autoFocus className="w-full h-8 rounded border border-gray-300 px-2 text-sm focus:outline-none focus:ring-1 focus:ring-teal-500" />
                    </td>
                    <td className="px-4 py-2 text-center">
                      <input type="checkbox" checked={edit.principal} onChange={e => setEdit(p => ({ ...p, principal: e.target.checked }))}
                        className="h-4 w-4 rounded border-gray-300 text-teal-600" />
                    </td>
                    <td className="px-4 py-2 text-center">
                      <input type="checkbox" checked={edit.activa} onChange={e => setEdit(p => ({ ...p, activa: e.target.checked }))}
                        className="h-4 w-4 rounded border-gray-300 text-teal-600" />
                    </td>
                    <td className="px-4 py-2 text-right">
                      <div className="flex gap-1 justify-end">
                        <button onClick={() => guardarEdit(b.id)} disabled={saving}
                          className="p-1.5 rounded text-teal-600 hover:bg-teal-100"><Check className="h-4 w-4" /></button>
                        <button onClick={() => setEditando(null)}
                          className="p-1.5 rounded text-gray-400 hover:bg-gray-100"><X className="h-4 w-4" /></button>
                      </div>
                    </td>
                  </>
                ) : (
                  <>
                    <td className="px-4 py-3 font-mono text-gray-500 text-xs">{b.codigo ?? '—'}</td>
                    <td className="px-4 py-3 font-medium text-gray-800">{b.nombre}</td>
                    <td className="px-4 py-3 text-center">
                      {b.principal && <Star className="h-4 w-4 text-yellow-500 mx-auto" />}
                    </td>
                    <td className="px-4 py-3 text-center">
                      <button onClick={() => toggleActiva(b)}
                        className={`text-xs px-2 py-0.5 rounded-full font-medium ${b.activa ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
                        {b.activa ? 'Activa' : 'Inactiva'}
                      </button>
                    </td>
                    <td className="px-4 py-3 text-right">
                      <button onClick={() => iniciarEdit(b)}
                        className="p-1.5 rounded text-gray-400 hover:text-teal-600 hover:bg-gray-100">
                        <Edit2 className="h-3.5 w-3.5" />
                      </button>
                    </td>
                  </>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { Button } from '@/components/ui/button'

interface Empresa {
  id: string
  nombre: string
  nit: string
  dv?: string | null
  razon_social?: string | null
  direccion?: string | null
  ciudad?: string | null
  departamento?: string | null
  pais?: string | null
  telefono?: string | null
  email?: string | null
  regimen?: string | null
  tipo_org?: string | null
}

interface Props { empresa: Empresa | null }

const REGIMENES = ['Responsable de IVA', 'No Responsable de IVA', 'Gran Contribuyente', 'Autorretenedor']
const TIPOS_ORG = ['Persona Natural', 'Persona Jurídica']

export function FormEmpresa({ empresa }: Props) {
  const [form, setForm] = useState<Omit<Empresa, 'id'>>({
    nombre:      empresa?.nombre      ?? '',
    nit:         empresa?.nit         ?? '',
    dv:          empresa?.dv          ?? '',
    razon_social: empresa?.razon_social ?? '',
    direccion:   empresa?.direccion   ?? '',
    ciudad:      empresa?.ciudad      ?? '',
    departamento: empresa?.departamento ?? '',
    pais:        empresa?.pais        ?? 'Colombia',
    telefono:    empresa?.telefono    ?? '',
    email:       empresa?.email       ?? '',
    regimen:     empresa?.regimen     ?? '',
    tipo_org:    empresa?.tipo_org    ?? '',
  })
  const [guardando, setGuardando] = useState(false)
  const [msg, setMsg] = useState<{ tipo: 'ok' | 'err'; texto: string } | null>(null)

  const set = (k: keyof typeof form, v: string) => setForm(p => ({ ...p, [k]: v }))

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setGuardando(true)
    setMsg(null)
    try {
      const res = await fetch('/api/configuracion/empresa', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form),
      })
      if (!res.ok) throw new Error((await res.json()).error ?? 'Error al guardar')
      setMsg({ tipo: 'ok', texto: 'Datos de la empresa actualizados.' })
    } catch (e: any) {
      setMsg({ tipo: 'err', texto: e.message })
    } finally {
      setGuardando(false)
    }
  }

  const field = (label: string, key: keyof typeof form, opts?: { type?: string; placeholder?: string }) => (
    <div className="flex flex-col gap-1">
      <label className="text-xs font-medium text-gray-600">{label}</label>
      <input
        type={opts?.type ?? 'text'}
        value={(form[key] as string) ?? ''}
        onChange={e => set(key, e.target.value)}
        placeholder={opts?.placeholder}
        className="h-9 rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
      />
    </div>
  )

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-6">
      {msg && (
        <div className={`rounded-lg px-4 py-3 text-sm ${msg.tipo === 'ok' ? 'bg-green-50 text-green-700 border border-green-200' : 'bg-red-50 text-red-700 border border-red-200'}`}>
          {msg.texto}
        </div>
      )}

      {/* Identificación */}
      <div className="rounded-xl border border-gray-200 bg-white p-6">
        <h3 className="text-sm font-semibold text-gray-700 mb-4">Identificación</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {field('Nombre comercial *', 'nombre', { placeholder: 'Nombre que aparece en documentos' })}
          {field('Razón social', 'razon_social', { placeholder: 'Razón social legal' })}
          <div className="flex gap-2">
            <div className="flex-1">{field('NIT *', 'nit', { placeholder: '123456789' })}</div>
            <div className="w-20">{field('DV', 'dv', { placeholder: '0' })}</div>
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-xs font-medium text-gray-600">Régimen</label>
            <select
              value={form.regimen ?? ''}
              onChange={e => set('regimen', e.target.value)}
              className="h-9 rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="">— Seleccionar —</option>
              {REGIMENES.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-xs font-medium text-gray-600">Tipo de organización</label>
            <select
              value={form.tipo_org ?? ''}
              onChange={e => set('tipo_org', e.target.value)}
              className="h-9 rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="">— Seleccionar —</option>
              {TIPOS_ORG.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>
        </div>
      </div>

      {/* Contacto y ubicación */}
      <div className="rounded-xl border border-gray-200 bg-white p-6">
        <h3 className="text-sm font-semibold text-gray-700 mb-4">Contacto y Ubicación</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {field('Dirección', 'direccion', { placeholder: 'Calle 123 # 45-67' })}
          {field('Ciudad', 'ciudad', { placeholder: 'Ipiales' })}
          {field('Departamento', 'departamento', { placeholder: 'Nariño' })}
          {field('País', 'pais', { placeholder: 'Colombia' })}
          {field('Teléfono', 'telefono', { type: 'tel', placeholder: '+57 300 000 0000' })}
          {field('Email', 'email', { type: 'email', placeholder: 'empresa@correo.com' })}
        </div>
      </div>

      <div className="flex justify-end">
        <Button type="submit" disabled={guardando}>
          {guardando ? 'Guardando…' : 'Guardar cambios'}
        </Button>
      </div>
    </form>
  )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { Button } from '@/components/ui/button'
import { Plus, Edit2, Check, X, ExternalLink } from 'lucide-react'

interface Transportadora {
  id: string; nombre: string; whatsapp: string | null; url_rastreo: string | null; activa: boolean
}

interface Props { transportadoras: Transportadora[] }

const EMPTY = { nombre: '', whatsapp: '', url_rastreo: '' }

export function FormTransportadoras({ transportadoras: inicial }: Props) {
  const router = useRouter()
  const [adding, setAdding]     = useState(false)
  const [editando, setEditando] = useState<string | null>(null)
  const [saving, setSaving]     = useState(false)
  const [nuevo, setNuevo]       = useState(EMPTY)
  const [edit, setEdit]         = useState({ nombre: '', whatsapp: '', url_rastreo: '', activa: true })

  async function guardarNuevo() {
    if (!nuevo.nombre.trim()) return
    setSaving(true)
    try {
      const res = await fetch('/api/configuracion/transportadoras', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(nuevo),
      })
      if (!res.ok) throw new Error((await res.json()).error)
      setAdding(false)
      setNuevo(EMPTY)
      router.refresh()
    } catch (e: any) {
      alert(e.message)
    } finally {
      setSaving(false)
    }
  }

  function iniciarEdit(t: Transportadora) {
    setEditando(t.id)
    setEdit({ nombre: t.nombre, whatsapp: t.whatsapp ?? '', url_rastreo: t.url_rastreo ?? '', activa: t.activa })
  }

  async function guardarEdit(id: string) {
    setSaving(true)
    try {
      const res = await fetch('/api/configuracion/transportadoras', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id, ...edit }),
      })
      if (!res.ok) throw new Error((await res.json()).error)
      setEditando(null)
      router.refresh()
    } catch (e: any) {
      alert(e.message)
    } finally {
      setSaving(false)
    }
  }

  async function toggleActiva(t: Transportadora) {
    await fetch('/api/configuracion/transportadoras', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: t.id, activa: !t.activa }),
    })
    router.refresh()
  }

  return (
    <div className="rounded-xl border border-gray-200 bg-white overflow-hidden">
      <div className="flex items-center justify-between px-5 py-4 border-b border-gray-100">
        <h3 className="text-sm font-semibold text-gray-700">{inicial.length} transportadora{inicial.length !== 1 ? 's' : ''}</h3>
        <Button size="sm" variant="outline" onClick={() => setAdding(true)} disabled={adding}>
          <Plus className="h-4 w-4 mr-1" /> Nueva
        </Button>
      </div>

      <table className="w-full text-sm">
        <thead className="bg-gray-50 border-b border-gray-100">
          <tr>
            <th className="px-4 py-3 text-left font-medium text-gray-500">Nombre</th>
            <th className="px-4 py-3 text-left font-medium text-gray-500">WhatsApp</th>
            <th className="px-4 py-3 text-left font-medium text-gray-500">URL rastreo</th>
            <th className="px-4 py-3 text-center font-medium text-gray-500">Estado</th>
            <th className="px-4 py-3" />
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          {adding && (
            <tr className="bg-indigo-50">
              <td className="px-4 py-2">
                <input value={nuevo.nombre} onChange={e => setNuevo(p => ({ ...p, nombre: e.target.value }))}
                  placeholder="Servientrega" autoFocus
                  className="w-full h-8 rounded border border-gray-300 px-2 text-sm focus:outline-none focus:ring-1 focus:ring-indigo-500" />
              </td>
              <td className="px-4 py-2">
                <input value={nuevo.whatsapp} onChange={e => setNuevo(p => ({ ...p, whatsapp: e.target.value }))}
                  placeholder="+57 300 000 0000"
                  className="w-full h-8 rounded border border-gray-300 px-2 text-sm focus:outline-none focus:ring-1 focus:ring-indigo-500" />
              </td>
              <td className="px-4 py-2">
                <input value={nuevo.url_rastreo} onChange={e => setNuevo(p => ({ ...p, url_rastreo: e.target.value }))}
                  placeholder="https://..."
                  className="w-full h-8 rounded border border-gray-300 px-2 text-sm focus:outline-none focus:ring-1 focus:ring-indigo-500" />
              </td>
              <td className="px-4 py-2 text-center text-gray-400 text-xs">—</td>
              <td className="px-4 py-2 text-right">
                <div className="flex gap-1 justify-end">
                  <button onClick={guardarNuevo} disabled={saving}
                    className="p-1.5 rounded text-indigo-600 hover:bg-indigo-100"><Check className="h-4 w-4" /></button>
                  <button onClick={() => setAdding(false)}
                    className="p-1.5 rounded text-gray-400 hover:bg-gray-100"><X className="h-4 w-4" /></button>
                </div>
              </td>
            </tr>
          )}

          {inicial.length === 0 && !adding ? (
            <tr><td colSpan={5} className="px-4 py-10 text-center text-gray-400">No hay transportadoras</td></tr>
          ) : inicial.map(t => (
            <tr key={t.id} className={`hover:bg-gray-50 ${!t.activa ? 'opacity-50' : ''}`}>
              {editando === t.id ? (
                <>
                  <td className="px-4 py-2">
                    <input value={edit.nombre} onChange={e => setEdit(p => ({ ...p, nombre: e.target.value }))} autoFocus
                      className="w-full h-8 rounded border border-gray-300 px-2 text-sm focus:outline-none focus:ring-1 focus:ring-indigo-500" />
                  </td>
                  <td className="px-4 py-2">
                    <input value={edit.whatsapp} onChange={e => setEdit(p => ({ ...p, whatsapp: e.target.value }))}
                      className="w-full h-8 rounded border border-gray-300 px-2 text-sm focus:outline-none focus:ring-1 focus:ring-indigo-500" />
                  </td>
                  <td className="px-4 py-2">
                    <input value={edit.url_rastreo} onChange={e => setEdit(p => ({ ...p, url_rastreo: e.target.value }))}
                      className="w-full h-8 rounded border border-gray-300 px-2 text-sm focus:outline-none focus:ring-1 focus:ring-indigo-500" />
                  </td>
                  <td className="px-4 py-2 text-center">
                    <input type="checkbox" checked={edit.activa} onChange={e => setEdit(p => ({ ...p, activa: e.target.checked }))}
                      className="h-4 w-4 rounded border-gray-300 text-indigo-600" />
                  </td>
                  <td className="px-4 py-2 text-right">
                    <div className="flex gap-1 justify-end">
                      <button onClick={() => guardarEdit(t.id)} disabled={saving}
                        className="p-1.5 rounded text-indigo-600 hover:bg-indigo-100"><Check className="h-4 w-4" /></button>
                      <button onClick={() => setEditando(null)}
                        className="p-1.5 rounded text-gray-400 hover:bg-gray-100"><X className="h-4 w-4" /></button>
                    </div>
                  </td>
                </>
              ) : (
                <>
                  <td className="px-4 py-3 font-medium text-gray-800">{t.nombre}</td>
                  <td className="px-4 py-3 text-gray-500 text-xs font-mono">{t.whatsapp ?? '—'}</td>
                  <td className="px-4 py-3">
                    {t.url_rastreo ? (
                      <a href={t.url_rastreo} target="_blank" rel="noreferrer"
                        className="flex items-center gap-1 text-blue-600 hover:underline text-xs">
                        <ExternalLink className="h-3 w-3" /> Rastrear
                      </a>
                    ) : <span className="text-gray-400 text-xs">—</span>}
                  </td>
                  <td className="px-4 py-3 text-center">
                    <button onClick={() => toggleActiva(t)}
