'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Modal } from '@/components/ui/modal'
import { formatCOP, formatFecha } from '@/utils/cn'
import { ClipboardList, CheckCircle, XCircle, Truck, FileText, Printer } from 'lucide-react'
import Link from 'next/link'

interface FormaPago { id: string; descripcion: string }
interface Linea {
  id: string; descripcion?: string; cantidad: number
  precio_unitario: number; descuento_porcentaje: number; total: number
  producto?: { codigo: string; descripcion: string } | null
  impuesto?: { porcentaje: number } | null
}
interface Pedido {
  id: string; numero: number; prefijo: string; fecha: string; fecha_vencimiento?: string | null
  estado: string; subtotal: number; total_iva: number; total_descuento: number; total: number
  observaciones?: string | null
  cliente?: { id?: string; razon_social?: string; numero_documento?: string; email?: string; telefono?: string } | null
  bodega?: { nombre?: string } | null
  lineas?: Linea[]
}

const BADGE_ESTADO: Record<string, 'default' | 'outline' | 'success' | 'warning' | 'danger' | 'info'> = {
  pendiente:  'warning',
  en_proceso: 'info',
  despachado: 'default',
  facturado:  'success',
  cancelado:  'danger',
}

interface Props { pedido: Pedido; formasPago: FormaPago[] }

export function DetallePedido({ pedido, formasPago }: Props) {
  const router = useRouter()
  const lineas = (pedido.lineas ?? []) as Linea[]
  const [accionando, setAccionando]   = useState(false)
  const [modalFact, setModalFact]     = useState(false)
  const [fpId, setFpId]               = useState(formasPago[0]?.id ?? '')
  const [vencimiento, setVencimiento] = useState(pedido.fecha)

  async function ejecutar(accion: string, extra?: object) {
    setAccionando(true)
    try {
      const res = await fetch(`/api/ventas/pedidos/${pedido.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ accion, ...extra }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Error')
      if (accion === 'facturar' && data.id) {
        router.push(`/ventas/facturas/${data.id}`)
      } else {
        router.refresh()
      }
    } catch (e: any) {
      alert(e.message)
    } finally {
      setAccionando(false)
      setModalFact(false)
    }
  }

  const activo = pedido.estado !== 'facturado' && pedido.estado !== 'cancelado'

  return (
    <div className="flex flex-col gap-6">
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <div className="flex flex-wrap items-start justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-purple-100">
              <ClipboardList className="h-5 w-5 text-purple-600" />
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h2 className="text-lg font-bold text-gray-900">{pedido.prefijo}{pedido.numero}</h2>
                <Badge variant={BADGE_ESTADO[pedido.estado] ?? 'outline'}>{pedido.estado.replace('_', ' ')}</Badge>
              </div>
              <p className="text-sm text-gray-500">Fecha: {formatFecha(pedido.fecha)}</p>
            </div>
          </div>
          <div className="flex flex-wrap gap-2">
            {pedido.estado === 'pendiente' && (
              <Button size="sm" onClick={() => ejecutar('en_proceso')} disabled={accionando}>
                <CheckCircle className="h-4 w-4 mr-1" /> En proceso
              </Button>
            )}
            {pedido.estado === 'en_proceso' && (
              <Button size="sm" onClick={() => ejecutar('despachar')} disabled={accionando}>
                <Truck className="h-4 w-4 mr-1" /> Despachar
              </Button>
            )}
            {(pedido.estado === 'pendiente' || pedido.estado === 'en_proceso' || pedido.estado === 'despachado') && (
              <Button size="sm" variant="success" onClick={() => setModalFact(true)} disabled={accionando}>
                <FileText className="h-4 w-4 mr-1" /> Facturar
              </Button>
            )}
            {activo && (
              <Button size="sm" variant="outline" onClick={() => ejecutar('cancelar')} disabled={accionando}>
                <XCircle className="h-4 w-4 mr-1" /> Cancelar
              </Button>
            )}
            <Link href={`/print/pedido/${pedido.id}`} target="_blank"
              className="inline-flex items-center gap-1 h-8 px-3 rounded-lg border border-gray-300 text-sm text-gray-600 hover:bg-gray-50 transition-colors">
              <Printer className="h-4 w-4" /> Imprimir
            </Link>
          </div>
        </div>
      </div>

      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <p className="text-xs font-semibold text-gray-500 uppercase mb-2">Cliente</p>
        <p className="font-semibold text-gray-900">{pedido.cliente?.razon_social ?? '—'}</p>
        {pedido.cliente?.numero_documento && <p className="text-sm text-gray-500">{pedido.cliente.numero_documento}</p>}
        {pedido.cliente?.email && <p className="text-sm text-gray-500">{pedido.cliente.email}</p>}
        {pedido.cliente?.telefono && <p className="text-sm text-gray-500">{pedido.cliente.telefono}</p>}
        {pedido.bodega?.nombre && <p className="text-sm text-gray-400 mt-1">Bodega: {pedido.bodega.nombre}</p>}
      </div>

      <div className="rounded-xl border border-gray-200 bg-white overflow-hidden">
        <table className="w-full text-sm">
          <thead className="bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="px-4 py-3 text-left font-semibold text-gray-600">Producto</th>
              <th className="px-4 py-3 text-right font-semibold text-gray-600">Cant.</th>
              <th className="px-4 py-3 text-right font-semibold text-gray-600">Precio</th>
              <th className="px-4 py-3 text-right font-semibold text-gray-600">IVA%</th>
              <th className="px-4 py-3 text-right font-semibold text-gray-600">Total</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {lineas.map((l, i) => (
              <tr key={l.id ?? i}>
                <td className="px-4 py-3">
                  <p className="font-medium text-gray-900">{l.producto?.descripcion ?? l.descripcion ?? '—'}</p>
                  {l.producto?.codigo && <p className="text-xs text-gray-400 font-mono">{l.producto.codigo}</p>}
                </td>
                <td className="px-4 py-3 text-right text-gray-700">{l.cantidad}</td>
                <td className="px-4 py-3 text-right font-mono text-gray-700">{formatCOP(l.precio_unitario)}</td>
                <td className="px-4 py-3 text-right text-gray-500">{l.impuesto?.porcentaje ?? 0}%</td>
                <td className="px-4 py-3 text-right font-mono font-medium text-gray-900">{formatCOP(l.total)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="flex justify-end">
        <div className="w-56 flex flex-col gap-1 text-sm">
          <div className="flex justify-between py-1 border-b border-gray-100"><span className="text-gray-600">Subtotal</span><span className="font-mono">{formatCOP(pedido.subtotal)}</span></div>
          {pedido.total_descuento > 0 && <div className="flex justify-between py-1 border-b border-gray-100"><span className="text-red-600">Descuento</span><span className="font-mono text-red-600">-{formatCOP(pedido.total_descuento)}</span></div>}
          <div className="flex justify-between py-1 border-b border-gray-100"><span className="text-gray-600">IVA</span><span className="font-mono">{formatCOP(pedido.total_iva)}</span></div>
          <div className="flex justify-between font-bold py-2 border-t-2 border-gray-800 mt-1"><span>TOTAL</span><span className="font-mono text-purple-700">{formatCOP(pedido.total)}</span></div>
        </div>
      </div>

      {pedido.observaciones && <p className="text-sm text-gray-500 italic px-1">{pedido.observaciones}</p>}

      <Modal open={modalFact} onClose={() => setModalFact(false)} titulo="Facturar Pedido">
        <div className="flex flex-col gap-4">
          <p className="text-sm text-gray-600">Selecciona forma de pago y vencimiento:</p>
          <div className="flex flex-col gap-1">
            <label className="text-xs font-medium text-gray-600">Forma de pago *</label>
            <select value={fpId} onChange={e => setFpId(e.target.value)}
              className="h-9 rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500">
              {formasPago.map(fp => <option key={fp.id} value={fp.id}>{fp.descripcion}</option>)}
            </select>
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-xs font-medium text-gray-600">Fecha vencimiento</label>
            <input type="date" value={vencimiento} onChange={e => setVencimiento(e.target.value)}
              className="h-9 rounded-lg border border-gray-300 px-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500" />
          </div>
          <div className="flex gap-2 justify-end pt-2">
            <Button variant="outline" size="sm" onClick={() => setModalFact(false)}>Cancelar</Button>
            <Button size="sm" disabled={accionando || !fpId}
              onClick={() => ejecutar('facturar', { forma_pago_id: fpId, vencimiento })}>
              {accionando ? 'Creando factura…' : 'Crear factura'}
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  )
}

'use client'

import { useState, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import { Button } from '@/components/ui/button'
import type { Cliente, Producto, Impuesto, Bodega } from '@/types'
import { formatCOP } from '@/utils/cn'
import { Plus, Trash2, AlertCircle } from 'lucide-react'

interface Linea {
  producto_id: string; descripcion: string; cantidad: number
  precio_unitario: number; descuento_porcentaje: number
  impuesto_id: string; iva_pct: number
}

function calcLinea(l: Linea) {
  const sub  = l.cantidad * l.precio_unitario
  const dct  = sub * (l.descuento_porcentaje / 100)
  const base = sub - dct
  const iva  = base * (l.iva_pct / 100)
  return { sub, dct, iva, total: base + iva }
}

interface Props {
  clientes:  Cliente[]
  productos: Producto[]
  impuestos: Impuesto[]
  bodegas:   Bodega[]
}

const hoy = new Date().toISOString().slice(0, 10)
const en15 = new Date(Date.now() + 15 * 86400000).toISOString().slice(0, 10)

export function FormPedido({ clientes, productos, impuestos, bodegas }: Props) {
  const router = useRouter()
  const [cliente_id, setClienteId] = useState('')
  const [bodega_id, setBodegaId]   = useState(bodegas.find(b => b.principal)?.id ?? bodegas[0]?.id ?? '')
  const [fecha, setFecha]          = useState(hoy)
  const [vencimiento, setVenc]     = useState(en15)
  const [observaciones, setObs]    = useState('')
  const [lineas, setLineas]        = useState<Linea[]>([])
  const [guardando, setGuardando]  = useState(false)
  const [error, setError]          = useState('')

  function agregarLinea() {
    const p0   = productos[0]
    const imp0 = impuestos.find(i => i.id === p0?.impuesto_id) ?? impuestos[0]
    setLineas(prev => [...prev, {
      producto_id: p0?.id ?? '', descripcion: p0?.descripcion ?? '',
      cantidad: 1, precio_unitario: p0?.precio_venta ?? 0,
      descuento_porcentaje: 0, impuesto_id: imp0?.id ?? '', iva_pct: imp0?.porcentaje ?? 0,
    }])
  }

  const handleProducto = useCallback((idx: number, producto_id: string) => {
    const p   = productos.find(x => x.id === producto_id)
    const imp = impuestos.find(i => i.id === p?.impuesto_id)
    setLineas(prev => prev.map((l, i) => i !== idx ? l : {
      ...l, producto_id, descripcion: p?.descripcion ?? '',
      precio_unitario: p?.precio_venta ?? 0,
      impuesto_id: imp?.id ?? '', iva_pct: imp?.porcentaje ?? 0,
    }))
  }, [productos, impuestos])

  function updateLinea(idx: number, field: keyof Linea, value: string | number) {
    setLineas(prev => prev.map((l, i) => {
      if (i !== idx) return l
      const u = { ...l, [field]: value }
      if (field === 'impuesto_id') u.iva_pct = impuestos.find(x => x.id === value)?.porcentaje ?? 0
      return u
    }))
  }

  const calcs    = lineas.map(calcLinea)
  const subtotal  = calcs.reduce((s, c) => s + c.sub,   0)
  const descuento = calcs.reduce((s, c) => s + c.dct,   0)
  const totalIva  = calcs.reduce((s, c) => s + c.iva,   0)
  const total     = calcs.reduce((s, c) => s + c.total, 0)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (!cliente_id)    { setError('Selecciona un cliente'); return }
    if (!lineas.length) { setError('Agrega al menos un producto'); return }
    setGuardando(true); setError('')
    try {
      const res = await fetch('/api/ventas/pedidos', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          cliente_id, bodega_id, fecha, vencimiento, observaciones: observaciones || null,
          lineas: lineas.map(l => ({
            producto_id: l.producto_id, descripcion: l.descripcion,
            cantidad: l.cantidad, precio_unitario: l.precio_unitario,
            descuento_porcentaje: l.descuento_porcentaje, impuesto_id: l.impuesto_id || null,
          })),
        }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Error al crear')
      router.push(`/ventas/pedidos/${data.id}`)
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'Error')
      setGuardando(false)
    }
  }

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-6">
      {/* Cabecera */}
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <h3 className="text-sm font-semibold text-gray-700 mb-4">Información general</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          <div className="sm:col-span-2 flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Cliente *</label>
            <select value={cliente_id} onChange={e => setClienteId(e.target.value)} required
              className="h-9 rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500">
              <option value="">— Seleccionar cliente —</option>
              {clientes.map(c => <option key={c.id} value={c.id}>{c.razon_social}</option>)}
            </select>
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Bodega *</label>
            <select value={bodega_id} onChange={e => setBodegaId(e.target.value)} required
              className="h-9 rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500">
              {bodegas.map(b => <option key={b.id} value={b.id}>{b.nombre}</option>)}
            </select>
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Fecha</label>
            <input type="date" value={fecha} onChange={e => setFecha(e.target.value)}
              className="h-9 rounded-lg border border-gray-300 px-3 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500" />
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Entrega estimada</label>
            <input type="date" value={vencimiento} onChange={e => setVenc(e.target.value)}
              className="h-9 rounded-lg border border-gray-300 px-3 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500" />
          </div>

          <div className="flex flex-col gap-1 sm:col-span-2 lg:col-span-3">
            <label className="text-sm font-medium text-gray-700">Observaciones</label>
            <textarea value={observaciones} onChange={e => setObs(e.target.value)} rows={2}
              placeholder="Instrucciones de entrega, notas..."
              className="rounded-lg border border-gray-300 px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-purple-500" />
          </div>
        </div>
      </div>

      {/* Líneas */}
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-sm font-semibold text-gray-700">Productos</h3>
          <Button type="button" size="sm" variant="outline" onClick={agregarLinea}>
            <Plus className="h-4 w-4 mr-1" /> Agregar línea
          </Button>
        </div>

        {lineas.length === 0 ? (
          <p className="text-center text-sm text-gray-400 py-8">No hay productos. Haz clic en "Agregar línea".</p>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-gray-200">
                  <th className="pb-2 text-left font-medium text-gray-600">Producto</th>
                  <th className="pb-2 text-right font-medium text-gray-600 w-20">Cant.</th>
                  <th className="pb-2 text-right font-medium text-gray-600 w-28">Precio</th>
                  <th className="pb-2 text-right font-medium text-gray-600 w-20">Dcto%</th>
                  <th className="pb-2 text-right font-medium text-gray-600 w-24">IVA</th>
                  <th className="pb-2 text-right font-medium text-gray-600 w-28">Total</th>
                  <th className="w-8" />
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {lineas.map((l, idx) => {
                  const c = calcLinea(l)
                  return (
                    <tr key={idx}>
                      <td className="py-2 pr-2">
                        <select value={l.producto_id} onChange={e => handleProducto(idx, e.target.value)}
                          className="w-full h-8 rounded-lg border border-gray-300 bg-white px-2 text-sm focus:outline-none focus:ring-1 focus:ring-purple-500">
                          {productos.map(p => <option key={p.id} value={p.id}>{p.descripcion}</option>)}
                        </select>
                      </td>
                      <td className="py-2 px-1">
                        <input type="number" min="1" step="1" value={l.cantidad}
                          onChange={e => updateLinea(idx, 'cantidad', parseFloat(e.target.value) || 0)}
                          className="w-full h-8 rounded-lg border border-gray-300 px-2 text-right text-sm focus:outline-none focus:ring-1 focus:ring-purple-500" />
                      </td>
                      <td className="py-2 px-1">
                        <input type="number" min="0" step="0.01" value={l.precio_unitario}
                          onChange={e => updateLinea(idx, 'precio_unitario', parseFloat(e.target.value) || 0)}
                          className="w-full h-8 rounded-lg border border-gray-300 px-2 text-right text-sm focus:outline-none focus:ring-1 focus:ring-purple-500" />
                      </td>
                      <td className="py-2 px-1">
                        <input type="number" min="0" max="100" step="0.1" value={l.descuento_porcentaje}
                          onChange={e => updateLinea(idx, 'descuento_porcentaje', parseFloat(e.target.value) || 0)}
                          className="w-full h-8 rounded-lg border border-gray-300 px-2 text-right text-sm focus:outline-none focus:ring-1 focus:ring-purple-500" />
                      </td>
                      <td className="py-2 px-1">
                        <select value={l.impuesto_id} onChange={e => updateLinea(idx, 'impuesto_id', e.target.value)}
                          className="w-full h-8 rounded-lg border border-gray-300 bg-white px-2 text-sm focus:outline-none focus:ring-1 focus:ring-purple-500">
                          <option value="">Sin IVA</option>
                          {impuestos.map(i => <option key={i.id} value={i.id}>{i.porcentaje}%</option>)}
                        </select>
                      </td>
                      <td className="py-2 pl-2 text-right font-mono font-medium text-gray-900">{formatCOP(c.total)}</td>
                      <td className="py-2 pl-1">
                        <button type="button" onClick={() => setLineas(prev => prev.filter((_, i) => i !== idx))}
                          className="text-gray-400 hover:text-red-500 transition-colors">
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Totales */}
      {lineas.length > 0 && (
        <div className="flex justify-end">
          <div className="w-64 rounded-xl border border-gray-200 bg-white p-4 flex flex-col gap-2 text-sm">
            <div className="flex justify-between text-gray-600"><span>Subtotal</span><span className="font-mono">{formatCOP(subtotal)}</span></div>
            {descuento > 0 && <div className="flex justify-between text-red-600"><span>Descuento</span><span className="font-mono">-{formatCOP(descuento)}</span></div>}
            <div className="flex justify-between text-gray-600"><span>IVA</span><span className="font-mono">{formatCOP(totalIva)}</span></div>
            <div className="flex justify-between font-bold text-gray-900 border-t border-gray-200 pt-2">
              <span>TOTAL</span><span className="font-mono text-purple-700">{formatCOP(total)}</span>
            </div>
          </div>
        </div>
      )}

      {error && (
        <div className="flex items-center gap-2 rounded-lg bg-red-50 border border-red-200 px-4 py-3 text-sm text-red-700">
          <AlertCircle className="h-4 w-4 shrink-0" /> {error}
        </div>
      )}

      <div className="flex gap-3 justify-end">
        <Button type="button" variant="outline" onClick={() => router.back()}>Cancelar</Button>
        <Button type="submit" disabled={guardando}
          className="bg-purple-600 hover:bg-purple-700 text-white">
          {guardando ? 'Guardando…' : 'Crear pedido'}
        </Button>
      </div>
    </form>
  )
}

'use client'

import { useState } from 'react'
import { UsuarioRow } from '@/lib/db/usuarios'
import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import { createClient } from '@/lib/supabase/client'
import { User, Lock, Check } from 'lucide-react'

interface Props { usuario: UsuarioRow }

export function FormPerfil({ usuario }: Props) {
  const supabase = createClient()
  const [nombre, setNombre]   = useState(usuario.nombre)
  const [telefono, setTelefono] = useState(usuario.telefono ?? '')
  const [newPass, setNewPass]  = useState('')
  const [confirmPass, setConfirmPass] = useState('')
  const [msgPerfil, setMsgPerfil] = useState('')
  const [msgPass, setMsgPass]     = useState('')
  const [savingP, setSavingP] = useState(false)
  const [savingC, setSavingC] = useState(false)

  async function guardarPerfil(e: React.FormEvent) {
    e.preventDefault()
    setSavingP(true)
    setMsgPerfil('')
    const res = await fetch(`/api/usuarios/${usuario.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ nombre, telefono: telefono || null }),
    })
    setSavingP(false)
    setMsgPerfil(res.ok ? '✅ Perfil actualizado' : '❌ Error al guardar')
    setTimeout(() => setMsgPerfil(''), 3000)
  }

  async function cambiarContrasena(e: React.FormEvent) {
    e.preventDefault()
    if (newPass !== confirmPass) { setMsgPass('❌ Las contraseñas no coinciden'); return }
    if (newPass.length < 8) { setMsgPass('❌ Mínimo 8 caracteres'); return }
    setSavingC(true)
    setMsgPass('')
    const { error } = await supabase.auth.updateUser({ password: newPass })
    setSavingC(false)
    if (error) { setMsgPass('❌ ' + error.message); return }
    setNewPass(''); setConfirmPass('')
    setMsgPass('✅ Contraseña actualizada')
    setTimeout(() => setMsgPass(''), 3000)
  }

  const rolNombre = usuario.roles?.nombre ?? 'sin rol'

  return (
    <div className="grid gap-6 max-w-2xl">

      {/* Info del usuario */}
      <div className="flex items-center gap-4 rounded-xl bg-gradient-to-r from-blue-50 to-indigo-50 border border-blue-100 p-5">
        <div className="flex h-16 w-16 items-center justify-center rounded-2xl bg-blue-600 text-white text-2xl font-bold shadow">
          {nombre.charAt(0).toUpperCase()}
        </div>
        <div>
          <p className="font-bold text-gray-900 text-lg">{nombre}</p>
          <p className="text-sm text-gray-500">{usuario.email}</p>
          <span className="inline-block mt-1 rounded-full bg-blue-100 px-2.5 py-0.5 text-xs font-medium text-blue-700 capitalize">
            {rolNombre}
          </span>
        </div>
      </div>

      {/* Datos personales */}
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <div className="flex items-center gap-2 mb-4">
          <User className="h-4 w-4 text-gray-400" />
          <h2 className="font-semibold text-gray-800">Datos personales</h2>
        </div>
        <form onSubmit={guardarPerfil} className="flex flex-col gap-4">
          <Input
            label="Nombre completo"
            value={nombre}
            onChange={e => setNombre(e.target.value)}
            required
          />
          <Input
            label="Teléfono / WhatsApp"
            placeholder="+57 300 000 0000"
            value={telefono}
            onChange={e => setTelefono(e.target.value)}
          />
          <Input
            label="Correo electrónico"
            value={usuario.email}
            disabled
            className="bg-gray-50 text-gray-400"
          />
          {msgPerfil && (
            <p className={`text-sm ${msgPerfil.startsWith('✅') ? 'text-green-600' : 'text-red-500'}`}>
              {msgPerfil}
            </p>
          )}
          <Button type="submit" disabled={savingP} className="w-fit">
            {savingP ? 'Guardando...' : 'Guardar cambios'}
          </Button>
        </form>
      </div>

      {/* Cambiar contraseña */}
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <div className="flex items-center gap-2 mb-4">
          <Lock className="h-4 w-4 text-gray-400" />
          <h2 className="font-semibold text-gray-800">Cambiar contraseña</h2>
        </div>
        <form onSubmit={cambiarContrasena} className="flex flex-col gap-4">
          <Input
            label="Nueva contraseña"
            type="password"
            placeholder="Mínimo 8 caracteres"
            value={newPass}
            onChange={e => setNewPass(e.target.value)}
            required
          />
          <Input
            label="Confirmar contraseña"
            type="password"
            placeholder="Repite la contraseña"
            value={confirmPass}
            onChange={e => setConfirmPass(e.target.value)}
            required
          />
          {msgPass && (
            <p className={`text-sm ${msgPass.startsWith('✅') ? 'text-green-600' : 'text-red-500'}`}>
              {msgPass}
            </p>
          )}
          <Button type="submit" variant="outline" disabled={savingC} className="w-fit">
            {savingC ? 'Actualizando...' : 'Cambiar contraseña'}
          </Button>
        </form>
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import type { Producto, Bodega, Familia, Fabricante, Impuesto } from '@/types'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Modal } from '@/components/ui/modal'
import { FormProducto } from './FormProducto'
import { AjusteStock } from './AjusteStock'
import { formatCOP, formatFecha } from '@/utils/cn'
import {
  Package, Pencil, ArrowUpCircle, ArrowDownCircle, RefreshCw,
  Layers, Warehouse, TrendingUp, AlertTriangle, Clock,
} from 'lucide-react'

interface Props {
  producto:    Producto
  bodegas:     Bodega[]
  familias:    Familia[]
  fabricantes: Fabricante[]
  impuestos:   Impuesto[]
  movimientos: MovimientoRow[]
}

interface MovimientoRow {
  id:         string
  tipo:       string
  cantidad:   number
  notas?:     string | null
  created_at: string
  bodega?:    { nombre: string } | null
}

const TIPO_LABELS: Record<string, { label: string; icon: typeof ArrowUpCircle; color: string }> = {
  entrada_compra:    { label: 'Entrada compra',   icon: ArrowUpCircle,   color: 'text-green-600' },
  salida_venta:      { label: 'Salida venta',      icon: ArrowDownCircle, color: 'text-red-600' },
  ajuste_positivo:   { label: 'Ajuste entrada',   icon: ArrowUpCircle,   color: 'text-blue-600' },
  ajuste_negativo:   { label: 'Ajuste salida',    icon: ArrowDownCircle, color: 'text-orange-600' },
  ajuste_inventario: { label: 'Ajuste inventario', icon: RefreshCw,       color: 'text-purple-600' },
}

export function DetalleProducto({ producto, bodegas, familias, fabricantes, impuestos, movimientos }: Props) {
  const router = useRouter()
  const [modalEditar, setModalEditar]   = useState(false)
  const [modalAjuste, setModalAjuste]   = useState(false)
  const [cargando, setCargando]         = useState(false)
  const [error, setError]               = useState('')

  const stockTotal = (producto.stock ?? []).reduce((s, st) => s + (st.cantidad ?? 0), 0)
  const stockBajo  = (producto.stock ?? []).some(s => s.cantidad_minima > 0 && s.cantidad <= s.cantidad_minima)
  const margen     = producto.precio_venta > 0
    ? Math.round(((producto.precio_venta - producto.precio_compra) / producto.precio_venta) * 100)
    : 0

  async function handleGuardar(datos: Record<string, unknown>) {
    setCargando(true); setError('')
    try {
      const res = await fetch(`/api/productos/${producto.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(datos),
      })
      if (!res.ok) { const b = await res.json(); throw new Error(b.error ?? 'Error') }
      setModalEditar(false)
      router.refresh()
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'Error')
    } finally {
      setCargando(false)
    }
  }

  return (
    <div className="flex flex-col gap-6">
      {/* Header */}
      <div className="flex flex-wrap items-start justify-between gap-4 rounded-2xl border border-gray-200 bg-white p-6">
        <div className="flex items-start gap-4">
          <div className="flex h-14 w-14 items-center justify-center rounded-xl bg-orange-100">
            <Package className="h-7 w-7 text-orange-600" />
          </div>
          <div>
            <div className="flex items-center gap-2 flex-wrap">
              <h1 className="text-xl font-bold text-gray-900">{producto.descripcion}</h1>
              <Badge variant={producto.activo ? 'success' : 'danger'}>{producto.activo ? 'Activo' : 'Inactivo'}</Badge>
              {stockBajo && (
                <span className="flex items-center gap-1 rounded-full bg-orange-100 px-2 py-0.5 text-xs font-medium text-orange-700">
                  <AlertTriangle className="h-3 w-3" /> Stock bajo
                </span>
              )}
            </div>
            <p className="text-sm font-mono text-gray-500 mt-0.5">{producto.codigo}</p>
            <div className="flex flex-wrap gap-2 mt-1">
              {(producto.familia as { nombre?: string } | null)?.nombre && (
                <span className="rounded-full bg-orange-50 px-2 py-0.5 text-xs text-orange-700">{(producto.familia as { nombre: string }).nombre}</span>
              )}
              {(producto.fabricante as { nombre?: string } | null)?.nombre && (
                <span className="rounded-full bg-gray-100 px-2 py-0.5 text-xs text-gray-600">{(producto.fabricante as { nombre: string }).nombre}</span>
              )}
              {producto.tiene_variantes && (
                <span className="flex items-center gap-1 rounded-full bg-blue-50 px-2 py-0.5 text-xs text-blue-700">
                  <Layers className="h-3 w-3" /> Con variantes
                </span>
              )}
            </div>
          </div>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => setModalAjuste(true)}>
            <Warehouse className="h-4 w-4 mr-1" /> Ajustar stock
          </Button>
          <Button size="sm" onClick={() => setModalEditar(true)}>
            <Pencil className="h-4 w-4 mr-1" /> Editar
          </Button>
        </div>
      </div>

      {/* KPIs */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {[
          { label: 'Precio venta',   value: formatCOP(producto.precio_venta),  color: 'text-green-700', bg: 'bg-green-50'  },
          { label: 'Precio compra',  value: formatCOP(producto.precio_compra), color: 'text-gray-700',  bg: 'bg-gray-50'   },
          { label: 'Margen bruto',   value: `${margen}%`,                      color: margen >= 30 ? 'text-green-700' : margen >= 15 ? 'text-yellow-700' : 'text-red-700', bg: 'bg-white' },
          { label: 'Stock total',    value: `${stockTotal.toLocaleString('es-CO')} ${producto.unidad_medida ?? 'UND'}`, color: stockBajo ? 'text-orange-700' : 'text-blue-700', bg: stockBajo ? 'bg-orange-50' : 'bg-blue-50' },
        ].map(k => (
          <div key={k.label} className={`rounded-xl border border-gray-100 ${k.bg} p-4`}>
            <p className="text-xs text-gray-500">{k.label}</p>
            <p className={`text-lg font-bold mt-1 ${k.color}`}>{k.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Stock por bodega */}
        <div className="rounded-xl border border-gray-200 bg-white p-5">
          <h3 className="text-sm font-semibold text-gray-700 mb-4 flex items-center gap-2">
            <Warehouse className="h-4 w-4 text-blue-500" /> Stock por bodega
          </h3>
          {(producto.stock ?? []).length === 0 ? (
            <p className="text-sm text-gray-400">Sin registro de stock</p>
          ) : (
            <div className="flex flex-col gap-2">
              {(producto.stock ?? []).map(s => {
                const bajo = s.cantidad_minima > 0 && s.cantidad <= s.cantidad_minima
                return (
                  <div key={s.id} className="flex items-center justify-between rounded-lg bg-gray-50 px-3 py-2">
                    <span className="text-sm text-gray-700">{(s.bodega as { nombre?: string } | null)?.nombre ?? 'Bodega'}</span>
                    <div className="flex items-center gap-2">
                      {bajo && <AlertTriangle className="h-3.5 w-3.5 text-orange-500" />}
                      <span className={`font-mono text-sm font-medium ${bajo ? 'text-orange-600' : 'text-gray-900'}`}>
                        {s.cantidad.toLocaleString('es-CO')}
                      </span>
                      {s.cantidad_minima > 0 && (
                        <span className="text-xs text-gray-400">/ mín {s.cantidad_minima}</span>
                      )}
                    </div>
                  </div>
                )
              })}
            </div>
          )}
        </div>

        {/* Variantes */}
        <div className="rounded-xl border border-gray-200 bg-white p-5">
          <h3 className="text-sm font-semibold text-gray-700 mb-4 flex items-center gap-2">
            <Layers className="h-4 w-4 text-purple-500" /> Variantes
          </h3>
          {!((producto as any).producto_variantes ?? []).length ? (
            <p className="text-sm text-gray-400">
              {producto.tiene_variantes ? 'Sin variantes registradas' : 'Producto sin variantes'}
            </p>
          ) : (
            <div className="flex flex-col gap-1">
              {((producto as any).producto_variantes ?? []).map((v: any) => (
                <div key={v.id} className="flex items-center justify-between rounded-lg bg-gray-50 px-3 py-1.5 text-sm">
                  <span className="text-gray-700">{[v.talla, v.color].filter(Boolean).join(' / ') || v.sku}</span>
                  {v.precio_venta && <span className="text-gray-500 font-mono">{formatCOP(v.precio_venta)}</span>}
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Info adicional */}
        <div className="rounded-xl border border-gray-200 bg-white p-5">
          <h3 className="text-sm font-semibold text-gray-700 mb-4 flex items-center gap-2">
            <TrendingUp className="h-4 w-4 text-green-500" /> Información
          </h3>
          <dl className="flex flex-col gap-2 text-sm">
            {producto.codigo_barras && (
              <div className="flex justify-between">
                <dt className="text-gray-500">Cód. barras</dt>
                <dd className="font-mono text-gray-700">{producto.codigo_barras}</dd>
              </div>
            )}
            {producto.unidad_medida && (
              <div className="flex justify-between">
                <dt className="text-gray-500">Unidad</dt>
                <dd className="text-gray-700">{producto.unidad_medida}</dd>
              </div>
            )}
            {(producto.impuesto as { porcentaje?: number } | null)?.porcentaje !== undefined && (
              <div className="flex justify-between">
                <dt className="text-gray-500">IVA</dt>
                <dd className="text-gray-700">{(producto.impuesto as { porcentaje: number }).porcentaje}%</dd>
              </div>
            )}
            {producto.precio_venta2 && (
              <div className="flex justify-between">
                <dt className="text-gray-500">P. mayorista</dt>
                <dd className="text-gray-700">{formatCOP(producto.precio_venta2)}</dd>
              </div>
            )}
            {producto.created_at && (
              <div className="flex justify-between">
                <dt className="text-gray-500">Creado</dt>
                <dd className="text-gray-700">{formatFecha(producto.created_at)}</dd>
              </div>
            )}
          </dl>
        </div>
      </div>

      {/* Movimientos */}
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <h3 className="text-sm font-semibold text-gray-700 mb-4 flex items-center gap-2">
          <Clock className="h-4 w-4 text-gray-400" /> Últimos movimientos de inventario
        </h3>
        {movimientos.length === 0 ? (
          <p className="text-sm text-gray-400">Sin movimientos registrados</p>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-gray-100">
                  <th className="pb-2 text-left text-xs font-medium text-gray-500">Fecha</th>
                  <th className="pb-2 text-left text-xs font-medium text-gray-500">Tipo</th>
                  <th className="pb-2 text-left text-xs font-medium text-gray-500">Bodega</th>
                  <th className="pb-2 text-right text-xs font-medium text-gray-500">Cantidad</th>
                  <th className="pb-2 text-left text-xs font-medium text-gray-500">Notas</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {movimientos.map(m => {
                  const meta = TIPO_LABELS[m.tipo] ?? { label: m.tipo, icon: RefreshCw, color: 'text-gray-500' }
                  const Icon = meta.icon
                  return (
                    <tr key={m.id} className="hover:bg-gray-50">
                      <td className="py-2 text-gray-500 font-mono text-xs">{formatFecha(m.created_at)}</td>
                      <td className="py-2">
                        <span className={`flex items-center gap-1 ${meta.color}`}>
                          <Icon className="h-3 w-3" />
                          {meta.label}
                        </span>
                      </td>
                      <td className="py-2 text-gray-500">{m.bodega?.nombre ?? '—'}</td>
                      <td className={`py-2 text-right font-mono font-medium ${m.cantidad >= 0 ? 'text-green-700' : 'text-red-700'}`}>
                        {m.cantidad >= 0 ? '+' : ''}{m.cantidad.toLocaleString('es-CO')}
                      </td>
                      <td className="py-2 text-gray-400 max-w-[150px] truncate">{m.notas ?? '—'}</td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Modal editar */}
      <Modal open={modalEditar} onClose={() => setModalEditar(false)} titulo="Editar producto" size="xl">
        {error && <div className="mb-4 rounded-lg bg-red-50 px-3 py-2 text-sm text-red-700">{error}</div>}
        <FormProducto
          inicial={producto}
          familias={familias}
          fabricantes={fabricantes}
          impuestos={impuestos}
          onGuardar={handleGuardar}
          onCancelar={() => setModalEditar(false)}
          cargando={cargando}
        />
      </Modal>

      {/* Modal ajuste */}
      <Modal open={modalAjuste} onClose={() => setModalAjuste(false)} titulo="Ajustar stock" size="sm">
        <AjusteStock
          producto={producto}
          bodegas={bodegas}
          onDone={() => { setModalAjuste(false); router.refresh() }}
          onCancel={() => setModalAjuste(false)}
        />
      </Modal>
    </div>
  )
}

'use client'

import { useState } from 'react'
