  id: string; numero: number; prefijo: string; fecha: string; fecha_vencimiento?: string | null
  estado: string; subtotal: number; total_iva: number; total_descuento: number; total: number
  observaciones?: string | null
  cliente?: { id?: string; razon_social?: string; numero_documento?: string; email?: string; telefono?: string } | null
  bodega?: { nombre?: string } | null
  lineas?: Linea[]
}

const BADGE_ESTADO: Record<string, 'default' | 'outline' | 'success' | 'warning' | 'danger' | 'info'> = {
  borrador:  'outline',
  enviada:   'info',
  entregada: 'success',
  facturada: 'default',
  cancelada: 'danger',
}

interface Props { remision: Remision; formasPago: FormaPago[] }

export function DetalleRemision({ remision, formasPago }: Props) {
  const router = useRouter()
  const lineas = (remision.lineas ?? []) as Linea[]
  const [accionando, setAccionando] = useState(false)
  const [modalFact, setModalFact]   = useState(false)
  const [fpId, setFpId]             = useState(formasPago[0]?.id ?? '')
  const [vencimiento, setVenc]      = useState(remision.fecha)

  async function ejecutar(accion: string, extra?: object) {
    setAccionando(true)
    try {
      const res = await fetch(`/api/ventas/remisiones/${remision.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ accion, ...extra }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Error')
      if (accion === 'facturar' && data.id) {
        router.push(`/ventas/facturas/${data.id}`)
      } else {
        router.refresh()
      }
    } catch (e: any) {
      alert(e.message)
    } finally {
      setAccionando(false)
      setModalFact(false)
    }
  }

  const activo = !['facturada', 'cancelada'].includes(remision.estado)

  return (
    <div className="flex flex-col gap-6">
      {/* Encabezado */}
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <div className="flex flex-wrap items-start justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-cyan-100">
              <Truck className="h-5 w-5 text-cyan-600" />
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h2 className="text-lg font-bold text-gray-900">{remision.prefijo}{remision.numero}</h2>
                <Badge variant={BADGE_ESTADO[remision.estado] ?? 'outline'}>{remision.estado}</Badge>
              </div>
              <p className="text-sm text-gray-500">Fecha: {formatFecha(remision.fecha)}</p>
              {remision.fecha_vencimiento && (
                <p className="text-xs text-gray-400">Entrega: {formatFecha(remision.fecha_vencimiento)}</p>
              )}
            </div>
          </div>
          <div className="flex flex-wrap gap-2">
            {remision.estado === 'borrador' && (
              <Button size="sm" onClick={() => ejecutar('enviar')} disabled={accionando}>
                <Send className="h-4 w-4 mr-1" /> Marcar enviada
              </Button>
            )}
            {remision.estado === 'enviada' && (
              <Button size="sm" variant="success" onClick={() => ejecutar('entregar')} disabled={accionando}>
                <CheckCircle className="h-4 w-4 mr-1" /> Marcar entregada
              </Button>
            )}
            {(remision.estado === 'borrador' || remision.estado === 'enviada' || remision.estado === 'entregada') && (
              <Button size="sm" variant="success" onClick={() => setModalFact(true)} disabled={accionando}>
                <FileText className="h-4 w-4 mr-1" /> Facturar
              </Button>
            )}
            {activo && (
              <Button size="sm" variant="outline" onClick={() => ejecutar('cancelar')} disabled={accionando}>
                <XCircle className="h-4 w-4 mr-1" /> Cancelar
              </Button>
            )}
            <Link href={`/print/remision/${remision.id}`} target="_blank"
              className="inline-flex items-center gap-1 h-8 px-3 rounded-lg border border-gray-300 text-sm text-gray-600 hover:bg-gray-50 transition-colors">
              <Printer className="h-4 w-4" /> Imprimir
            </Link>
          </div>
        </div>
      </div>

      {/* Cliente */}
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <p className="text-xs font-semibold text-gray-500 uppercase mb-2">Cliente</p>
        <p className="font-semibold text-gray-900">{remision.cliente?.razon_social ?? '—'}</p>
        {remision.cliente?.numero_documento && <p className="text-sm text-gray-500">{remision.cliente.numero_documento}</p>}
        {remision.cliente?.email    && <p className="text-sm text-gray-500">{remision.cliente.email}</p>}
        {remision.cliente?.telefono && <p className="text-sm text-gray-500">{remision.cliente.telefono}</p>}
        {remision.bodega?.nombre && <p className="text-sm text-gray-400 mt-1">Bodega: {remision.bodega.nombre}</p>}
      </div>

      {/* Líneas */}
      <div className="rounded-xl border border-gray-200 bg-white overflow-hidden">
        <table className="w-full text-sm">
          <thead className="bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="px-4 py-3 text-left font-semibold text-gray-600">Producto</th>
              <th className="px-4 py-3 text-right font-semibold text-gray-600">Cant.</th>
              <th className="px-4 py-3 text-right font-semibold text-gray-600">Precio</th>
              <th className="px-4 py-3 text-right font-semibold text-gray-600">IVA%</th>
              <th className="px-4 py-3 text-right font-semibold text-gray-600">Total</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {lineas.map((l, i) => (
              <tr key={l.id ?? i}>
                <td className="px-4 py-3">
                  <p className="font-medium text-gray-900">{l.producto?.descripcion ?? l.descripcion ?? '—'}</p>
                  {l.producto?.codigo && <p className="text-xs text-gray-400 font-mono">{l.producto.codigo}</p>}
                </td>
                <td className="px-4 py-3 text-right text-gray-700">{l.cantidad}</td>
                <td className="px-4 py-3 text-right font-mono text-gray-700">{formatCOP(l.precio_unitario)}</td>
                <td className="px-4 py-3 text-right text-gray-500">{l.impuesto?.porcentaje ?? 0}%</td>
                <td className="px-4 py-3 text-right font-mono font-medium text-gray-900">{formatCOP(l.total)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Totales */}
      <div className="flex justify-end">
        <div className="w-56 flex flex-col gap-1 text-sm">
          <div className="flex justify-between py-1 border-b border-gray-100"><span className="text-gray-600">Subtotal</span><span className="font-mono">{formatCOP(remision.subtotal)}</span></div>
          {remision.total_descuento > 0 && <div className="flex justify-between py-1"><span className="text-red-600">Descuento</span><span className="font-mono text-red-600">-{formatCOP(remision.total_descuento)}</span></div>}
          <div className="flex justify-between py-1 border-b border-gray-100"><span className="text-gray-600">IVA</span><span className="font-mono">{formatCOP(remision.total_iva)}</span></div>
          <div className="flex justify-between font-bold py-2 border-t-2 border-gray-800 mt-1"><span>TOTAL</span><span className="font-mono text-cyan-700">{formatCOP(remision.total)}</span></div>
        </div>
      </div>

      {remision.observaciones && (
        <p className="text-sm text-gray-500 italic px-1">{remision.observaciones}</p>
      )}

      {/* Modal facturar */}
      <Modal open={modalFact} onClose={() => setModalFact(false)} titulo="Facturar Remisión">
        <div className="flex flex-col gap-4">
          <p className="text-sm text-gray-600">Selecciona forma de pago y vencimiento para crear la factura:</p>
          <div className="flex flex-col gap-1">
            <label className="text-xs font-medium text-gray-600">Forma de pago *</label>
            <select value={fpId} onChange={e => setFpId(e.target.value)}
              className="h-9 rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-cyan-500">
              {formasPago.map(fp => <option key={fp.id} value={fp.id}>{fp.descripcion}</option>)}
            </select>
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-xs font-medium text-gray-600">Fecha vencimiento</label>
            <input type="date" value={vencimiento} onChange={e => setVenc(e.target.value)}
              className="h-9 rounded-lg border border-gray-300 px-3 text-sm focus:outline-none focus:ring-2 focus:ring-cyan-500" />
          </div>
          <div className="flex gap-2 justify-end pt-2">
            <Button variant="outline" size="sm" onClick={() => setModalFact(false)}>Cancelar</Button>
            <Button size="sm" disabled={accionando || !fpId}
              onClick={() => ejecutar('facturar', { forma_pago_id: fpId, vencimiento })}>
              {accionando ? 'Creando factura…' : 'Crear factura'}
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  )
}

'use client'

import { useState, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import { Button } from '@/components/ui/button'
import type { Cliente, Producto, Impuesto, Bodega } from '@/types'
import { formatCOP } from '@/utils/cn'
import { Plus, Trash2, AlertCircle } from 'lucide-react'

interface Linea {
  producto_id: string; descripcion: string; cantidad: number
  precio_unitario: number; descuento_porcentaje: number
  impuesto_id: string; iva_pct: number
}

function calcLinea(l: Linea) {
  const sub  = l.cantidad * l.precio_unitario
  const dct  = sub * (l.descuento_porcentaje / 100)
  const base = sub - dct
  const iva  = base * (l.iva_pct / 100)
  return { sub, dct, iva, total: base + iva }
}

interface Props {
  clientes:  Cliente[]
  productos: Producto[]
  impuestos: Impuesto[]
  bodegas:   Bodega[]
}

const hoy = new Date().toISOString().slice(0, 10)
const en7  = new Date(Date.now() + 7 * 86400000).toISOString().slice(0, 10)

export function FormRemision({ clientes, productos, impuestos, bodegas }: Props) {
  const router = useRouter()
  const [cliente_id, setClienteId] = useState('')
  const [bodega_id, setBodegaId]   = useState(bodegas.find(b => b.principal)?.id ?? bodegas[0]?.id ?? '')
  const [fecha, setFecha]          = useState(hoy)
  const [vencimiento, setVenc]     = useState(en7)
  const [observaciones, setObs]    = useState('')
  const [lineas, setLineas]        = useState<Linea[]>([])
  const [guardando, setGuardando]  = useState(false)
  const [error, setError]          = useState('')

  function agregarLinea() {
    const p0   = productos[0]
    const imp0 = impuestos.find(i => i.id === p0?.impuesto_id) ?? impuestos[0]
    setLineas(prev => [...prev, {
      producto_id: p0?.id ?? '', descripcion: p0?.descripcion ?? '',
      cantidad: 1, precio_unitario: p0?.precio_venta ?? 0,
      descuento_porcentaje: 0, impuesto_id: imp0?.id ?? '', iva_pct: imp0?.porcentaje ?? 0,
    }])
  }

  const handleProducto = useCallback((idx: number, producto_id: string) => {
    const p   = productos.find(x => x.id === producto_id)
    const imp = impuestos.find(i => i.id === p?.impuesto_id)
    setLineas(prev => prev.map((l, i) => i !== idx ? l : {
      ...l, producto_id, descripcion: p?.descripcion ?? '',
      precio_unitario: p?.precio_venta ?? 0,
      impuesto_id: imp?.id ?? '', iva_pct: imp?.porcentaje ?? 0,
    }))
  }, [productos, impuestos])

  function updateLinea(idx: number, field: keyof Linea, value: string | number) {
    setLineas(prev => prev.map((l, i) => {
      if (i !== idx) return l
      const u = { ...l, [field]: value }
      if (field === 'impuesto_id') u.iva_pct = impuestos.find(x => x.id === value)?.porcentaje ?? 0
      return u
    }))
  }

  const calcs    = lineas.map(calcLinea)
  const subtotal  = calcs.reduce((s, c) => s + c.sub,   0)
  const descuento = calcs.reduce((s, c) => s + c.dct,   0)
  const totalIva  = calcs.reduce((s, c) => s + c.iva,   0)
  const total     = calcs.reduce((s, c) => s + c.total, 0)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (!cliente_id)    { setError('Selecciona un cliente'); return }
    if (!lineas.length) { setError('Agrega al menos un producto'); return }
    setGuardando(true); setError('')
    try {
      const res = await fetch('/api/ventas/remisiones', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          cliente_id, bodega_id, fecha, vencimiento, observaciones: observaciones || null,
          lineas: lineas.map(l => ({
            producto_id: l.producto_id, descripcion: l.descripcion,
            cantidad: l.cantidad, precio_unitario: l.precio_unitario,
            descuento_porcentaje: l.descuento_porcentaje, impuesto_id: l.impuesto_id || null,
          })),
        }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error ?? 'Error al crear')
      router.push(`/ventas/remisiones/${data.id}`)
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'Error')
      setGuardando(false)
    }
  }

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-6">
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <h3 className="text-sm font-semibold text-gray-700 mb-4">Información general</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          <div className="sm:col-span-2 flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Cliente *</label>
            <select value={cliente_id} onChange={e => setClienteId(e.target.value)} required
              className="h-9 rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-cyan-500">
              <option value="">— Seleccionar cliente —</option>
              {clientes.map(c => <option key={c.id} value={c.id}>{c.razon_social}</option>)}
            </select>
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Bodega *</label>
            <select value={bodega_id} onChange={e => setBodegaId(e.target.value)} required
              className="h-9 rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-cyan-500">
              {bodegas.map(b => <option key={b.id} value={b.id}>{b.nombre}</option>)}
            </select>
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Fecha</label>
            <input type="date" value={fecha} onChange={e => setFecha(e.target.value)}
              className="h-9 rounded-lg border border-gray-300 px-3 text-sm focus:outline-none focus:ring-2 focus:ring-cyan-500" />
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Fecha de entrega</label>
            <input type="date" value={vencimiento} onChange={e => setVenc(e.target.value)}
              className="h-9 rounded-lg border border-gray-300 px-3 text-sm focus:outline-none focus:ring-2 focus:ring-cyan-500" />
          </div>
          <div className="flex flex-col gap-1 sm:col-span-2 lg:col-span-3">
            <label className="text-sm font-medium text-gray-700">Observaciones</label>
            <textarea value={observaciones} onChange={e => setObs(e.target.value)} rows={2}
              placeholder="Instrucciones de despacho, dirección de entrega..."
              className="rounded-lg border border-gray-300 px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-cyan-500" />
          </div>
        </div>
      </div>

      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-sm font-semibold text-gray-700">Artículos a despachar</h3>
          <Button type="button" size="sm" variant="outline" onClick={agregarLinea}>
            <Plus className="h-4 w-4 mr-1" /> Agregar línea
          </Button>
        </div>
        {lineas.length === 0 ? (
          <p className="text-center text-sm text-gray-400 py-8">No hay artículos. Haz clic en "Agregar línea".</p>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-gray-200">
                  <th className="pb-2 text-left font-medium text-gray-600">Producto</th>
                  <th className="pb-2 text-right font-medium text-gray-600 w-20">Cant.</th>
                  <th className="pb-2 text-right font-medium text-gray-600 w-28">Precio</th>
                  <th className="pb-2 text-right font-medium text-gray-600 w-20">Dcto%</th>
                  <th className="pb-2 text-right font-medium text-gray-600 w-24">IVA</th>
                  <th className="pb-2 text-right font-medium text-gray-600 w-28">Total</th>
                  <th className="w-8" />
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {lineas.map((l, idx) => {
                  const c = calcLinea(l)
                  return (
                    <tr key={idx}>
                      <td className="py-2 pr-2">
                        <select value={l.producto_id} onChange={e => handleProducto(idx, e.target.value)}
                          className="w-full h-8 rounded-lg border border-gray-300 bg-white px-2 text-sm focus:outline-none focus:ring-1 focus:ring-cyan-500">
                          {productos.map(p => <option key={p.id} value={p.id}>{p.descripcion}</option>)}
                        </select>
                      </td>
                      <td className="py-2 px-1">
                        <input type="number" min="1" step="1" value={l.cantidad}
                          onChange={e => updateLinea(idx, 'cantidad', parseFloat(e.target.value) || 0)}
                          className="w-full h-8 rounded-lg border border-gray-300 px-2 text-right text-sm focus:outline-none focus:ring-1 focus:ring-cyan-500" />
                      </td>
                      <td className="py-2 px-1">
                        <input type="number" min="0" step="0.01" value={l.precio_unitario}
                          onChange={e => updateLinea(idx, 'precio_unitario', parseFloat(e.target.value) || 0)}
                          className="w-full h-8 rounded-lg border border-gray-300 px-2 text-right text-sm focus:outline-none focus:ring-1 focus:ring-cyan-500" />
                      </td>
                      <td className="py-2 px-1">
                        <input type="number" min="0" max="100" step="0.1" value={l.descuento_porcentaje}
                          onChange={e => updateLinea(idx, 'descuento_porcentaje', parseFloat(e.target.value) || 0)}
                          className="w-full h-8 rounded-lg border border-gray-300 px-2 text-right text-sm focus:outline-none focus:ring-1 focus:ring-cyan-500" />
                      </td>
                      <td className="py-2 px-1">
                        <select value={l.impuesto_id} onChange={e => updateLinea(idx, 'impuesto_id', e.target.value)}
                          className="w-full h-8 rounded-lg border border-gray-300 bg-white px-2 text-sm focus:outline-none focus:ring-1 focus:ring-cyan-500">
                          <option value="">Sin IVA</option>
                          {impuestos.map(i => <option key={i.id} value={i.id}>{i.porcentaje}%</option>)}
                        </select>
                      </td>
                      <td className="py-2 pl-2 text-right font-mono font-medium text-gray-900">{formatCOP(c.total)}</td>
                      <td className="py-2 pl-1">
                        <button type="button" onClick={() => setLineas(prev => prev.filter((_, i) => i !== idx))}
                          className="text-gray-400 hover:text-red-500 transition-colors">
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {lineas.length > 0 && (
        <div className="flex justify-end">
          <div className="w-64 rounded-xl border border-gray-200 bg-white p-4 flex flex-col gap-2 text-sm">
            <div className="flex justify-between text-gray-600"><span>Subtotal</span><span className="font-mono">{formatCOP(subtotal)}</span></div>
            {descuento > 0 && <div className="flex justify-between text-red-600"><span>Descuento</span><span className="font-mono">-{formatCOP(descuento)}</span></div>}
            <div className="flex justify-between text-gray-600"><span>IVA</span><span className="font-mono">{formatCOP(totalIva)}</span></div>
            <div className="flex justify-between font-bold text-gray-900 border-t border-gray-200 pt-2">
              <span>TOTAL</span><span className="font-mono text-cyan-700">{formatCOP(total)}</span>
            </div>
          </div>
        </div>
      )}

      {error && (
        <div className="flex items-center gap-2 rounded-lg bg-red-50 border border-red-200 px-4 py-3 text-sm text-red-700">
          <AlertCircle className="h-4 w-4 shrink-0" /> {error}
        </div>
      )}

      <div className="flex gap-3 justify-end">
        <Button type="button" variant="outline" onClick={() => router.back()}>Cancelar</Button>
        <Button type="submit" disabled={guardando}
          className="bg-cyan-600 hover:bg-cyan-700 text-white">
          {guardando ? 'Guardando…' : 'Crear remisión'}
        </Button>
      </div>
    </form>
  )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Wrench, ChevronRight, CheckCircle, XCircle, Package } from 'lucide-react'
import { formatFecha } from '@/utils/cn'

interface Servicio {
  id: string; numero: number; tipo: string; estado: string; prioridad: string
  servicio: string; direccion?: string | null; diagnostico?: string | null
  solucion?: string | null; observaciones?: string | null
  fecha_inicio?: string | null; fecha_promesa?: string | null; fecha_cierre?: string | null
  created_at: string
  cliente?: { id?: string; razon_social?: string; numero_documento?: string; email?: string; telefono?: string } | null
}

const BADGE_ESTADO: Record<string, 'default' | 'outline' | 'success' | 'warning' | 'danger' | 'info'> = {
  recibida:    'outline',
  diagnostico: 'warning',
  en_proceso:  'info',
  listo:       'default',
  entregado:   'success',
  cancelado:   'danger',
}

const FLUJO = ['recibida', 'diagnostico', 'en_proceso', 'listo', 'entregado']

const PRIORIDAD_COLOR: Record<string, string> = {
  baja:   'bg-gray-100 text-gray-600',
  normal: 'bg-blue-100 text-blue-700',
  alta:   'bg-orange-100 text-orange-700',
  urgente:'bg-red-100 text-red-700',
}

interface Props { servicio: Servicio }

export function DetalleServicio({ servicio }: Props) {
  const router = useRouter()
  const [accionando, setAccionando] = useState(false)
  const [guardando, setGuardando]   = useState(false)
  const [notas, setNotas]           = useState({
    diagnostico:  servicio.diagnostico  ?? '',
    solucion:     servicio.solucion     ?? '',
    observaciones:servicio.observaciones ?? '',
  })

  const activo = !['entregado', 'cancelado'].includes(servicio.estado)
  const idxActual = FLUJO.indexOf(servicio.estado)
  const siguiente = FLUJO[idxActual + 1] ?? null

  async function avanzar() {
    if (!siguiente) return
    setAccionando(true)
    try {
      const res = await fetch(`/api/ventas/servicios/${servicio.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ estado: siguiente }),
      })
      if (!res.ok) throw new Error((await res.json()).error)
      router.refresh()
    } catch (e: any) { alert(e.message) }
    finally { setAccionando(false) }
  }

  async function cancelar() {
    if (!confirm('¿Cancelar esta orden de servicio?')) return
    setAccionando(true)
    try {
      await fetch(`/api/ventas/servicios/${servicio.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ estado: 'cancelado' }),
      })
      router.refresh()
    } catch (e: any) { alert(e.message) }
    finally { setAccionando(false) }
  }

  async function guardarNotas() {
    setGuardando(true)
    try {
      await fetch(`/api/ventas/servicios/${servicio.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(notas),
      })
      router.refresh()
    } catch {}
    finally { setGuardando(false) }
  }

  const LABELS: Record<string, string> = {
    recibida: 'Recibida', diagnostico: 'Diagnóstico', en_proceso: 'En proceso',
    listo: 'Listo p/entrega', entregado: 'Entregado',
  }
  const NEXT_LABEL: Record<string, string> = {
    recibida: 'Iniciar diagnóstico', diagnostico: 'Iniciar reparación',
    en_proceso: 'Marcar listo', listo: 'Marcar entregado',
  }

  return (
    <div className="flex flex-col gap-6">
      {/* Header */}
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <div className="flex flex-wrap items-start justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-violet-100">
              <Wrench className="h-5 w-5 text-violet-600" />
            </div>
            <div>
              <div className="flex items-center gap-2 flex-wrap">
                <h2 className="text-lg font-bold text-gray-900">Orden #{servicio.numero}</h2>
                <Badge variant={BADGE_ESTADO[servicio.estado] ?? 'outline'}>{servicio.estado.replace('_', ' ')}</Badge>
                <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium ${PRIORIDAD_COLOR[servicio.prioridad] ?? 'bg-gray-100 text-gray-600'}`}>
                  {servicio.prioridad}
                </span>
                <span className="text-xs text-gray-400 capitalize">{servicio.tipo}</span>
              </div>
              <p className="text-sm text-gray-500">Ingreso: {servicio.fecha_inicio ? formatFecha(servicio.fecha_inicio) : '—'}</p>
              {servicio.fecha_promesa && <p className="text-xs text-gray-400">Promesa: {formatFecha(servicio.fecha_promesa)}</p>}
            </div>
          </div>
          <div className="flex flex-wrap gap-2">
            {activo && siguiente && (
              <Button size="sm" variant="success" onClick={avanzar} disabled={accionando}>
                <ChevronRight className="h-4 w-4 mr-1" /> {NEXT_LABEL[servicio.estado] ?? 'Avanzar'}
              </Button>
            )}
            {activo && (
              <Button size="sm" variant="outline" onClick={cancelar} disabled={accionando}>
                <XCircle className="h-4 w-4 mr-1" /> Cancelar
              </Button>
            )}
          </div>
        </div>

        {/* Progreso */}
        <div className="flex items-center gap-1 mt-4 overflow-x-auto">
          {FLUJO.map((paso, i) => {
            const completado = i <= idxActual
            const actual     = paso === servicio.estado
            return (
              <div key={paso} className="flex items-center gap-1 shrink-0">
                <div className={`flex items-center gap-1.5 px-2 py-1 rounded-full text-xs font-medium ${
                  actual      ? 'bg-violet-600 text-white' :
                  completado  ? 'bg-violet-100 text-violet-700' : 'bg-gray-100 text-gray-400'
                }`}>
                  {completado && !actual && <CheckCircle className="h-3 w-3" />}
                  {LABELS[paso]}
                </div>
                {i < FLUJO.length - 1 && <ChevronRight className="h-3 w-3 text-gray-300 shrink-0" />}
              </div>
            )
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Cliente */}
        <div className="rounded-xl border border-gray-200 bg-white p-5">
          <p className="text-xs font-semibold text-gray-500 uppercase mb-3">Cliente</p>
          <p className="font-semibold text-gray-900">{servicio.cliente?.razon_social ?? '—'}</p>
          {servicio.cliente?.numero_documento && <p className="text-sm text-gray-500 mt-0.5">{servicio.cliente.numero_documento}</p>}
          {servicio.cliente?.email    && <p className="text-sm text-gray-500">{servicio.cliente.email}</p>}
          {servicio.cliente?.telefono && <p className="text-sm text-gray-500">{servicio.cliente.telefono}</p>}
        </div>

        {/* Descripción del servicio */}
        <div className="rounded-xl border border-gray-200 bg-white p-5">
          <p className="text-xs font-semibold text-gray-500 uppercase mb-3">Servicio solicitado</p>
          <p className="text-gray-800">{servicio.servicio}</p>
          {servicio.direccion && (
            <p className="text-sm text-gray-500 mt-2">Dirección: {servicio.direccion}</p>
          )}
          {servicio.fecha_cierre && (
            <p className="text-sm text-green-600 mt-2">Entregado: {formatFecha(servicio.fecha_cierre)}</p>
          )}
        </div>
      </div>

      {/* Notas técnicas */}
      <div className="rounded-xl border border-gray-200 bg-white p-5">
        <p className="text-xs font-semibold text-gray-500 uppercase mb-4">Notas técnicas</p>
        <div className="flex flex-col gap-4">
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Diagnóstico</label>
            <textarea value={notas.diagnostico} onChange={e => setNotas(p => ({ ...p, diagnostico: e.target.value }))}
              rows={2} disabled={!activo} placeholder="Diagnóstico del técnico..."
              className="rounded-lg border border-gray-300 px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-violet-500 disabled:bg-gray-50 disabled:text-gray-400" />
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Solución aplicada</label>
            <textarea value={notas.solucion} onChange={e => setNotas(p => ({ ...p, solucion: e.target.value }))}
              rows={2} disabled={!activo} placeholder="Descripción de la solución..."
              className="rounded-lg border border-gray-300 px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-violet-500 disabled:bg-gray-50 disabled:text-gray-400" />
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-700">Observaciones adicionales</label>
            <textarea value={notas.observaciones} onChange={e => setNotas(p => ({ ...p, observaciones: e.target.value }))}
              rows={2} disabled={!activo} placeholder="Piezas reemplazadas, accesorios entregados..."
              className="rounded-lg border border-gray-300 px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-violet-500 disabled:bg-gray-50 disabled:text-gray-400" />
          </div>
          {activo && (
            <div className="flex justify-end">
              <Button size="sm" variant="outline" onClick={guardarNotas} disabled={guardando}>
                {guardando ? 'Guardando…' : 'Guardar notas'}
              </Button>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { Moon, Sun } from 'lucide-react'

export function ThemeToggle() {
  const [dark, setDark] = useState(false)

  useEffect(() => {
    const saved = localStorage.getItem('theme')
    if (saved === 'dark' || (!saved && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setDark(true)
      document.documentElement.classList.add('dark')
    }
  }, [])

  function toggle() {
    const next = !dark
    setDark(next)
    if (next) {
      document.documentElement.classList.add('dark')
      localStorage.setItem('theme', 'dark')
    } else {
      document.documentElement.classList.remove('dark')
      localStorage.setItem('theme', 'light')
    }
  }

  return (
    <button
      onClick={toggle}
      title={dark ? 'Modo claro' : 'Modo oscuro'}
      className="rounded-full p-1.5 text-gray-500 hover:bg-gray-100 dark:text-gray-400 dark:hover:bg-gray-700 transition-colors"
    >
      {dark ? <Sun className="h-5 w-5" /> : <Moon className="h-5 w-5" />}
    </button>
  )
}
